import jwt
import json
from datetime import datetime, timezone
from typing import Optional, Union


def decode_jwt_unverified(token: str) -> dict:
    """
    Decode a JWT token WITHOUT verifying the signature.
    Useful for inspecting token contents during debugging.
    
    WARNING: Do not use this for authentication/authorization decisions.
    """
    # Decode without verification
    header = jwt.get_unverified_header(token)
    payload = jwt.decode(token, options={"verify_signature": False})
    
    return {
        "header": header,
        "payload": payload
    }


def decode_jwt_verified(token: str, secret: str, algorithms: Optional[list] = None,
                        audience: Optional[str] = None, issuer: Optional[str] = None) -> dict:
    """
    Decode and verify a JWT token with full signature verification.
    
    Args:
        token: The JWT token string
        secret: The secret key or public key for verification
        algorithms: List of allowed algorithms (default: ["HS256"])
        audience: Expected audience claim
        issuer: Expected issuer claim
    
    Returns:
        Dictionary with header, payload, and verification status
    """
    if algorithms is None:
        algorithms = ["HS256"]
    
    decode_options = {}
    kwargs = {"algorithms": algorithms}
    
    if audience:
        kwargs["audience"] = audience
    if issuer:
        kwargs["issuer"] = issuer
    
    try:
        header = jwt.get_unverified_header(token)
        payload = jwt.decode(token, secret, **kwargs)
        return {
            "header": header,
            "payload": payload,
            "verified": True,
            "error": None
        }
    except jwt.ExpiredSignatureError:
        payload = jwt.decode(token, options={"verify_signature": False})
        header = jwt.get_unverified_header(token)
        return {
            "header": header,
            "payload": payload,
            "verified": False,
            "error": "Token has expired"
        }
    except jwt.InvalidSignatureError:
        payload = jwt.decode(token, options={"verify_signature": False})
        header = jwt.get_unverified_header(token)
        return {
            "header": header,
            "payload": payload,
            "verified": False,
            "error": "Invalid signature"
        }
    except jwt.InvalidTokenError as e:
        return {
            "header": None,
            "payload": None,
            "verified": False,
            "error": f"Invalid token: {str(e)}"
        }


def inspect_jwt(token: str, secret: Optional[str] = None) -> None:
    """
    Pretty-print JWT token contents for debugging.
    If a secret is provided, also verifies the signature.
    
    Args:
        token: The JWT token string
        secret: Optional secret key for verification
    """
    print("=" * 60)
    print("JWT TOKEN INSPECTION")
    print("=" * 60)
    
    # Count segments
    parts = token.split(".")
    print(f"\nToken segments: {len(parts)}")
    if len(parts) != 3:
        print(f"WARNING: Expected 3 segments, got {len(parts)}. Invalid JWT format.")
        return
    
    print(f"Token length: {len(token)} characters")
    
    try:
        decoded = decode_jwt_unverified(token)
    except Exception as e:
        print(f"\nERROR: Failed to decode token: {e}")
        return
    
    # Header
    print(f"\n--- HEADER ---")
    print(json.dumps(decoded["header"], indent=2))
    
    # Payload
    print(f"\n--- PAYLOAD ---")
    payload = decoded["payload"]
    print(json.dumps(payload, indent=2, default=str))
    
    # Time-related claims analysis
    print(f"\n--- TIME ANALYSIS ---")
    now = datetime.now(timezone.utc)
    print(f"Current time (UTC): {now.isoformat()}")
    
    time_claims = {
        "iat": "Issued At",
        "exp": "Expires At",
        "nbf": "Not Before"
    }
    
    for claim, label in time_claims.items():
        if claim in payload:
            timestamp = payload[claim]
            dt = datetime.fromtimestamp(timestamp, tz=timezone.utc)
            diff = dt - now
            
            if claim == "exp":
                status = "EXPIRED" if diff.total_seconds() < 0 else "VALID"
                print(f"  {label}: {dt.isoformat()} ({status}, "
                      f"{'expired' if diff.total_seconds() < 0 else 'expires in'} "
                      f"{abs(int(diff.total_seconds()))}s)")
            elif claim == "nbf":
                status = "ACTIVE" if diff.total_seconds() <= 0 else "NOT YET VALID"
                print(f"  {label}: {dt.isoformat()} ({status})")
            else:
                print(f"  {label}: {dt.isoformat()} ({abs(int(diff.total_seconds()))}s ago)")
        else:
            print(f"  {label}: NOT PRESENT")
    
    # Standard claims
    print(f"\n--- STANDARD CLAIMS ---")
    standard_claims = {
        "iss": "Issuer",
        "sub": "Subject",
        "aud": "Audience",
        "jti": "JWT ID"
    }
    for claim, label in standard_claims.items():
        value = payload.get(claim, "NOT PRESENT")
        print(f"  {label} ({claim}): {value}")
    
    # Custom claims
    all_standard = set(time_claims.keys()) | set(standard_claims.keys())
    custom_claims = {k: v for k, v in payload.items() if k not in all_standard}
    if custom_claims:
        print(f"\n--- CUSTOM CLAIMS ---")
        for key, value in custom_claims.items():
            print(f"  {key}: {json.dumps(value, default=str)}")
    
    # Signature verification
    if secret:
        print(f"\n--- SIGNATURE VERIFICATION ---")
        result = decode_jwt_verified(token, secret)
        if result["verified"]:
            print("  ✅ Signature is VALID")
        else:
            print(f"  ❌ Signature verification FAILED: {result['error']}")
    else:
        print(f"\n--- SIGNATURE VERIFICATION ---")
        print("  ⚠️  No secret provided, signature not verified")
    
    print("\n" + "=" * 60)


def create_debug_token(payload: dict, secret: str = "debug-secret",
                       algorithm: str = "HS256",
                       expires_in_seconds: int = 3600) -> str:
    """
    Create a JWT token for testing/debugging purposes.
    
    Args:
        payload: Dictionary of claims to include
        secret: Secret key for signing
        algorithm: Signing algorithm
        expires_in_seconds: Token expiration time in seconds
    
    Returns:
        Encoded JWT token string
    """
    now = datetime.now(timezone.utc)
    default_claims = {
        "iat": now,
        "exp": datetime.fromtimestamp(now.timestamp() + expires_in_seconds, tz=timezone.utc),
        "nbf": now
    }
    
    # Merge default claims with provided payload (payload takes precedence)
    token_payload = {**default_claims, **payload}
    
    token = jwt.encode(token_payload, secret, algorithm=algorithm)
    return token


def compare_tokens(token1: str, token2: str) -> None:
    """
    Compare two JWT tokens side by side for debugging.
    Highlights differences in claims.
    """
    print("=" * 60)
